### Tool Use

```ts
import { generateText, tool } from "ai";
import { z } from "zod";

const { text, toolCalls } = await generateText({
  model: anthropic("claude-sonnet-4-6"),
  tools: {
    getWeather: tool({
      description: "取得城市天氣",
      parameters: z.object({
        city: z.string()
      }),
      execute: async ({ city }) => {
        const data = await fetch(`/weather/${city}`);
        return await data.json();
      }
    })
  },
  prompt: "台北現在幾度？",
  maxSteps: 5
});
```


